SELECT ID, WAREHOUSE_CODE, WAREHOUSE_NAME, COMPANY_ID, COMPANY_NAME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME, DEL_FLAG, DELETE_BY, DELETE_BY_NAME, DELETE_TIME FROM E_MATERIAL_WAREHOUSE
DEL_FLAG = 0
AND WAREHOUSE_CODE LIKE #{warehouseCodePattern}
AND WAREHOUSE_NAME LIKE #{warehouseNamePattern}
AND COMPANY_ID = #{companyId}
ORDER BY CREATE_TIME DESC

SELECT COUNT(*)
FROM E_MATERIAL_WAREHOUSE
WHERE WAREHOUSE_CODE = #{warehouseCode}
AND DEL_FLAG = 0

    AND ID != #{id}
